package main

import (
	"encoding/gob"
	"fmt"
	"io/ioutil"
	"os"
	"path/filepath"
	"sync"
	"time"
)

type Session struct {
	UserID       string
	Preferences  map[string]interface{}
	Permissions  []string
	LastAccessed time.Time
}

type SessionManager struct {
	sessions map[string]*Session
	mu       sync.RWMutex
	dir      string
}

func NewSessionManager(dir string) *SessionManager {
	return &SessionManager{
		sessions: make(map[string]*Session),
		dir:      dir,
	}
}

func (sm *SessionManager) CreateSession(userID string) string {
	sessionID := fmt.Sprintf("%d", time.Now().Unix())
	
	session := &Session{
		UserID:       userID,
		Preferences:  make(map[string]interface{}),
		Permissions:  make([]string, 0),
		LastAccessed: time.Now(),
	}
	
	sm.mu.Lock()
	sm.sessions[sessionID] = session
	sm.mu.Unlock()
	
	sm.saveSessionToFile(sessionID, session)
	
	return sessionID
}

func (sm *SessionManager) GetSession(sessionID string) (*Session, bool) {
	sm.mu.RLock()
	session, exists := sm.sessions[sessionID]
	sm.mu.RUnlock()
	
	if !exists {
		session, err := sm.loadSessionFromFile(sessionID)
		if err != nil {
			return nil, false
		}
		sm.mu.Lock()
		sm.sessions[sessionID] = session
		sm.mu.Unlock()
		return session, true
	}
	
	session.LastAccessed = time.Now()
	sm.saveSessionToFile(sessionID, session)
	
	return session, true
}

func (sm *SessionManager) UpdateSession(sessionID string, updateFunc func(*Session)) error {
	sm.mu.Lock()
	session, exists := sm.sessions[sessionID]
	if !exists {
		sm.mu.Unlock()
		return fmt.Errorf("session not found")
	}
	
	updateFunc(session)
	session.LastAccessed = time.Now()
	
	sm.mu.Unlock()
	
	return sm.saveSessionToFile(sessionID, session)
}

func (sm *SessionManager) DeleteSession(sessionID string) {
	sm.mu.Lock()
	delete(sm.sessions, sessionID)
	sm.mu.Unlock()
	
	sm.deleteSessionFile(sessionID)
}

func (sm *SessionManager) saveSessionToFile(sessionID string, session *Session) error {
	filename := filepath.Join(sm.dir, sessionID+".gob")
	
	file, err := os.Create(filename)
	if err != nil {
		return err
	}
	defer file.Close()
	
	encoder := gob.NewEncoder(file)
	return encoder.Encode(session)
}

func (sm *SessionManager) loadSessionFromFile(sessionID string) (*Session, error) {
	filename := filepath.Join(sm.dir, sessionID+".gob")
	
	file, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
	defer file.Close()
	
	var session Session
	decoder := gob.NewDecoder(file)
	err = decoder.Decode(&session)
	if err != nil {
		return nil, err
	}
	
	return &session, nil
}

func (sm *SessionManager) deleteSessionFile(sessionID string) {
	filename := filepath.Join(sm.dir, sessionID+".gob")
	os.Remove(filename)
}

func (sm *SessionManager) CleanupExpiredSessions(expiration time.Duration) {
	now := time.Now()
	
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	for sessionID, session := range sm.sessions {
		if now.Sub(session.LastAccessed) > expiration {
			delete(sm.sessions, sessionID)
			sm.deleteSessionFile(sessionID)
		}
	}
}

